temperature = 25

if temperature > 30:
    print('Жарко!')
elif temperature > 20:
    print('Тепло')
elif temperature > 10:
    print('Прохладно')
else:
    print('Холодно')

# Выведет: Тепло

# Однострочный if (только для очень простых случаев)
status = 'взрослый' if temperature > 18 else 'нет'  # тернарный оператор
print(status)
